const Path = () => {
  return (
    <section id="duong-dan">
      <div className="container">
        <a href="./index.html">
          <span>Trang chủ</span>
        </a>
        <span>
          <i className="fa fa-angle-right" aria-hidden="true" />
        </span>
        <a href="./shop-list.html" className="duong-dan-active">
          <span>Sản phẩm</span>
        </a>
      </div>
    </section>
  );
};
export default Path;
